// RegisterOAuthFacadeServiceHandlerFromEndpoint is same as RegisterOAuthFacadeServiceHandler but
// automatically dials to "endpoint" and closes the connection when "ctx" gets done.
func RegisterOAuthFacadeServiceHandlerFromEndpoint(ctx context.Context, mux *runtime.ServeMux, endpoint string, opts []grpc.DialOption) (err error) {
	conn, err := grpc.NewClient(endpoint, opts...)
	if err != nil {
		return err
	}
	defer func() {
		if err != nil {
			if cerr := conn.Close(); cerr != nil {
				grpclog.Errorf("Failed to close conn to %s: %v", endpoint, cerr)
			}
			return
		}
		go func() {
			<-ctx.Done()
			if cerr := conn.Close(); cerr != nil {
				grpclog.Errorf("Failed to close conn to %s: %v", endpoint, cerr)
			}
		}()
	}()
	return RegisterOAuthFacadeServiceHandler(ctx, mux, conn)
}

